-- Enrichment marathon batch: Traggo, Transistor, Transmission, Tray.io, Trello, Trengo, Trigger.dev, Trilium Notes

-- ── Traggo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Traggo is a free, open-source, self-hosted time tracking tool that logs time spans using flexible tags instead of fixed tasks or projects.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Traggo Review: Self-Hosted Tag-Based Time Tracking$q$, seo_title),
  seo_meta_description = COALESCE($q$Traggo is a free, open-source, self-hosted time tracker that uses flexible tags instead of tasks. See features, setup requirements, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Traggo is a free, open-source, self-hosted time tracking application built with a Go backend and released under the GPL-3.0 license. Unlike conventional time trackers such as Toggl Track or Clockify that organize time around fixed projects and tasks, Traggo uses a tag-based model: every logged time span can carry multiple key-value tags (for example project, client, or activity type), which users can then filter and analyze in custom reports and statistics views. Because there is no predefined task hierarchy, Traggo adapts to almost any workflow without requiring users to pre-plan a project structure. The application ships as a Docker container, making it straightforward to self-host on a home server, NAS, or VPS, and it exposes a GraphQL API for integrations and custom tooling. Traggo supports multiple users on a single instance, a visual timeline for reviewing logged spans, and tag-based statistics for understanding how time is distributed. As with most self-hosted, open-source tools, there is no vendor cloud, subscription fee, or third-party data access involved; users control their own infrastructure and data entirely. The project originated as a community open-source effort (hosted under the traggo GitHub organization) rather than a funded company, and active development has continued through community forks such as Lutonite/traggo. Traggo is best compared to other self-hosted time trackers like Kimai, and to cloud services like Toggl Track or Clockify for teams who prioritize data ownership and tag-based flexibility over managed convenience. It has no official pricing since it is free to run; the only cost is the infrastructure needed to host it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd816c0d6-616e-417e-bf4c-30fc9be88134';

