-- ── Transistor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Transistor is a bootstrapped podcast hosting and analytics platform that lets creators publish unlimited shows and distribute to every major podcast app from one dashboard.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Transistor.fm Review: Podcast Hosting and Analytics$q$, seo_title),
  seo_meta_description = COALESCE($q$Transistor is a podcast hosting platform with unlimited shows, downloads-based pricing from 19 dollars a month, analytics, and private podcast support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Transistor.fm is a podcast hosting and analytics platform built by Justin Jackson and Jon Buda, who met at the XOXO Festival in Portland in 2014 and officially launched the product on August 1, 2018. The company is bootstrapped rather than venture-funded and operates as a small, distributed team with a nominal headquarters in Chicago, Illinois. Transistor's key differentiator is its pricing model: rather than charging per podcast show, as many competitors like Libsyn or Buzzsprout historically have, Transistor allows unlimited podcasts and unlimited episode storage on every plan, with price instead scaling by monthly download volume. Plans are Starter at 19 dollars a month for up to 10,000 downloads, Professional at 49 dollars a month for up to 50,000 downloads, and Business at 99 dollars a month for up to 150,000 downloads, with additional download blocks billed beyond those limits. Every plan includes one-click distribution to Apple Podcasts, Spotify, Amazon Music, and other major directories via RSS, a built-in podcast website with SEO-friendly episode pages, an embeddable audio player, private podcast support for premium or membership content, team member accounts, and an analytics dashboard built around IAB-certified download measurement. This unlimited-shows structure makes Transistor a popular choice for podcast networks and agencies managing several shows under one account, as well as solo creators who want simple, predictable pricing. It is commonly compared to Buzzsprout, Libsyn, Podbean, and Captivate, with Transistor generally seen as a more modern, design-forward alternative aimed at professional and business podcasters rather than absolute beginners on a shoestring budget, since it has no permanent free tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fc2d5e9c-d0f2-485e-b895-ac90c8c8411f';

