-- ── Transmission ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Transmission is a free, open-source, cross-platform BitTorrent client known for its lightweight footprint, clean interface, and native apps for macOS, Linux, and other Unix systems.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Transmission BitTorrent Client: Free and Open Source$q$, seo_title),
  seo_meta_description = COALESCE($q$Transmission is a free, open-source BitTorrent client for macOS, Linux, and Unix, known for its lightweight design and clean interface since 2005.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Transmission is a free, open-source BitTorrent client whose development began as a volunteer-driven project in 2005. It is released under the GNU General Public License, with some components under the MIT License, and is maintained today by a community of contributors rather than a company. Transmission offers native applications for macOS and various Linux and Unix desktop environments, a lightweight command-line daemon for headless servers and NAS devices, and a built-in web interface for remote management, making it one of the most widely deployed BitTorrent clients on self-hosted infrastructure. It gained early prominence when Ubuntu adopted it as the default BitTorrent client in January 2008, and it remains the default or a commonly bundled client on distributions including Linux Mint, Fedora, and the GNOME flavor of openSUSE. The project is known for its minimalist philosophy: no ads, no bundled toolbars, and no monetization schemes, in contrast to some historically ad-supported clients like uTorrent. Version 4.0, released in 2023, was a major milestone that added support for BitTorrent v2 and hybrid torrents, IPv6 peer blocklists, and a completely redesigned, mobile-friendly web client, and the project has continued shipping incremental 4.x releases since. Transmission is typically compared to qBittorrent, which offers a broader built-in feature set such as integrated search and RSS automation, and to uTorrent, which has drawn criticism over the years for bundled software and ads; Transmission's appeal instead rests on its simplicity, low resource usage, and trustworthiness as a genuinely free and open tool, particularly for server and NAS-based torrenting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae1278c1-c356-40cb-b81c-795513168fe4';

