-- ── Tray.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tray.io, rebranded Tray.ai, is an enterprise integration platform as a service (iPaaS) that lets technical and business teams build API integrations, workflow automations, and AI agents with a visual, low-code builder.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (sales-assisted pricing)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$101-250 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tray.io (Tray.ai) Review: Enterprise iPaaS Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Tray.io, now Tray.ai, is an enterprise integration and automation platform with visual workflow building and AI agent capabilities. See pricing and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tray.io was founded in 2012 by Rich Waldron, Alistair Russell, and Dominic Lewis, who met while studying together in the UK and initially ran a web agency before building the platform. The company is now headquartered in San Francisco, California, and has raised more than 100 million dollars in venture funding from investors including Spark Capital, True Ventures, and GGV Capital, with a valuation reported around 600 million dollars. Between 2018 and 2022 the company grew from roughly 500,000 dollars to approximately 50 million dollars in annual recurring revenue. In 2024, Tray.io rebranded to Tray.ai to reflect a strategic pivot toward AI-native automation, while keeping its core positioning as an enterprise integration platform as a service, or iPaaS, and has been recognized as a two-time Visionary in Gartner's Magic Quadrant for iPaaS. The platform provides a visual, low-code workflow builder, a universal connector framework covering hundreds of pre-built integrations, and, post-rebrand, tools for building AI agents that can act across connected systems. Tray targets mid-market and enterprise customers rather than the self-serve small-business audience that tools like Zapier or Make focus on, offering deeper governance features such as single sign-on, audit logging, and multiple workspaces for departmental separation. Pricing is entirely sales-assisted with no public self-serve rate or free tier; published tiers include a Pro plan built around 250,000 starter task credits and three workspaces, a Team plan with 500,000 credits and twenty workspaces, and an Enterprise plan with 750,000-plus credits, unlimited workspaces, and dedicated customer success support, with third-party sources estimating Pro-level contracts starting in the range of several hundred dollars per month and Enterprise contracts reaching tens of thousands of dollars annually.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5f2efd75-b393-44ab-a643-86bbadb40c49';

