-- ── Trengo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Trengo is a Netherlands-based omnichannel customer engagement platform that unifies email, WhatsApp, live chat, social media, and voice into one shared team inbox with AI-powered automation.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$EUR125/month (approximately $133/month)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Utrecht, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$Trengo Review: Omnichannel Customer Engagement Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Trengo unifies WhatsApp, email, chat, and social channels into one inbox. See pricing plans from EUR125 a month, key features, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Trengo is an omnichannel customer engagement platform founded in 2017 and headquartered in Utrecht, Netherlands. The company has raised roughly 38 million dollars in funding, including a 36 million dollar Series A round backed by investors such as Insight Partners and Peak, and has grown to more than 50 employees serving customers primarily across Europe. Trengo's product combines a shared team inbox with WhatsApp Business API integration, live chat, email, social media channels such as Instagram and Facebook, and VoIP calling, all managed from a single unified interface alongside AI-powered chatbots and automation rules for routing and triaging conversations. This WhatsApp-first, channel-unifying approach has made Trengo especially popular with European e-commerce brands and small-to-midsize customer service and sales teams that rely heavily on messaging apps rather than traditional email or phone support. Published pricing includes three self-serve tiers priced in euros: Essentials at 125 euros a month for 5 users and 100 conversations, Boost at 185 euros a month for 5 users and 300 conversations, and Pro at 310 euros a month for 5 users and 1,000 conversations, plus a custom-priced Enterprise tier for larger deployments. Trengo is commonly compared to Front, Zendesk, Intercom, and HubSpot Service Hub; its main differentiator against these larger, more US-centric competitors is its deep, native WhatsApp Business integration and strong footprint among European and e-commerce customer service teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '463b249f-58f5-4f62-8f21-0f807fd8bd65';

