-- ── Trigger.dev ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Trigger.dev is an open-source TypeScript platform for building and running long-running background jobs, AI agent workflows, and durable tasks with built-in retries, queues, and observability.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $10/month)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Trigger.dev Review: Open-Source Background Jobs Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Trigger.dev is an open-source TypeScript platform for background jobs and AI workflows. See pricing from 10 dollars a month and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Trigger.dev was founded in 2022 by Matt Aitken, Eric Allam, Dan Patel, and James Ritchie, and is headquartered in London, United Kingdom. The company went through Y Combinator's Winter 2023 batch and raised a seed round in the range of 3 to 3.5 million dollars. Trigger.dev is an open-source platform, with its core released under an open-source license and self-hostable, built specifically for developers writing TypeScript who need to run long-running background jobs, durable tasks, and AI agent workflows reliably, complete with automatic retries, task queues, elastic scaling, and full observability and tracing of every run. It is distinct from general-purpose distributed workflow engines such as Temporal in that it is TypeScript-first, ships as a fully-managed cloud platform out of the box, and is explicitly positioned around AI agent and background job use cases rather than being a broad, language-agnostic orchestration engine. The free plan includes 5 dollars of monthly usage credits along with 20 concurrent runs, 10 schedules, and 1 day of log retention; the Hobby plan is 10 dollars a month with more credits and higher limits; the Pro plan is 50 dollars a month with 200 or more concurrent runs, 1,000 or more schedules, 30-day log retention, and dedicated Slack support; and an Enterprise tier offers custom log retention, single sign-on, and SOC 2 and penetration test reports. Beyond the base plan fee, usage is billed per second of task compute time plus a small per-run invocation fee. Trigger.dev is commonly compared to Inngest, Temporal, and no-code automation tools like Zapier or Make, but it specifically targets engineering teams building code-first background jobs and AI agents rather than non-technical business users.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'caa46b4a-ddf7-473a-8793-845e45dd40b3';

