-- ── Trilium Notes ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Trilium Notes is a free, open-source, self-hosted hierarchical note-taking application for building large personal knowledge bases, now maintained by the community as TriliumNext.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Trilium Notes Review: Open-Source Hierarchical Note App$q$, seo_title),
  seo_meta_description = COALESCE($q$Trilium Notes is a free, self-hosted, open-source note-taking app with unlimited hierarchy, note cloning, and a WYSIWYG editor. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Trilium Notes was originally created by a developer known as zadam and first publicly released on December 25, 2017, as a free, open-source, self-hosted note-taking application under the AGPL-3.0 license, built for creating large personal knowledge bases. It is often positioned as a privacy-respecting, self-hosted alternative to Evernote, OneNote, and Roam Research. Its signature design choice is organizing notes as an unlimited-depth hierarchical tree rather than flat notebooks or folders, and it supports note cloning, which lets a single note appear in multiple places in that hierarchy without duplicating its content. All data is stored locally in a SQLite database, and users can optionally run a self-hosted sync server to keep notes consistent across devices, with no cloud dependency, subscription fee, or telemetry involved. The editor is a WYSIWYG interface supporting Markdown-style shortcuts, tables, images, math expressions, and syntax-highlighted code blocks, and the application also includes a built-in calendar view, a Kanban board view, and a browser web-clipper extension for saving pages and screenshots directly into the note tree. In January 2024, the original developer moved the project into maintenance mode, prompting a group of community contributors led by Elian Doran to fork the project as TriliumNext to keep active development going. The fork grew to roughly 2,700 stars independently, and the original repository, which had accumulated around 22,000 stars, was later transferred to the TriliumNext organization, which now maintains the project going forward simply as Trilium Notes. As fully free, self-hosted, open-source software, Trilium Notes has no pricing tiers or paid version.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8a1e8900-232b-487e-a707-161bf160047b';

