INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Tag-based time entries$q$, $q$Log time spans and attach unlimited custom key-value tags instead of choosing from a fixed project or task list.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Timeline visualization$q$, $q$Review and edit logged time spans on a visual timeline for quick auditing and corrections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Tag-based reporting$q$, $q$Generate statistics and reports aggregated by any tag combination, such as client or activity type.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Multi-user support$q$, $q$Run a single self-hosted instance shared by multiple users, each with their own tracked history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$GraphQL API$q$, $q$Query and manipulate time-tracking data programmatically for custom integrations and dashboards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Docker-based deployment$q$, $q$Ships as a Docker container for straightforward self-hosting on a server, NAS, or VPS.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Open-source, GPL-3.0 licensed$q$, $q$Full source code is publicly available and free to modify, audit, or self-host indefinitely.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Data ownership and privacy$q$, $q$All tracked time data stays on infrastructure the user controls, with no third-party access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Completely free with no subscription fees or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Full control and privacy over tracked time data through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Highly flexible tag-based model adapts to almost any workflow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Lightweight Docker deployment makes self-hosting relatively simple$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Open-source codebase can be audited, modified, or extended by anyone$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Requires technical comfort with Docker and self-hosting to get started$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$No official managed cloud option for users who prefer not to self-host$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$No official native mobile apps, relying on the browser-based web client$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Smaller community and slower release cadence than commercial time trackers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Lacks built-in invoicing or client-billing tools found in commercial alternatives$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Is Traggo free to use?$q$, $q$Yes. Traggo is fully open-source under the GPL-3.0 license with no paid plans; the only cost is hosting it yourself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Do I need to self-host Traggo?$q$, $q$Yes, Traggo has no official hosted cloud service, so you need to run it yourself, typically via Docker on a server, NAS, or VPS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$How does Traggo differ from tools like Toggl Track?$q$, $q$Traggo replaces the traditional project and task hierarchy with flexible tags, and it is self-hosted rather than a paid cloud subscription.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Does Traggo support multiple users?$q$, $q$Yes, a single self-hosted Traggo instance can support multiple user accounts, each tracking their own time.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Is there a mobile app for Traggo?$q$, $q$There is no official native mobile app; Traggo is used through its web-based interface, which is accessible from a mobile browser.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Does Traggo have an API?$q$, $q$Yes, Traggo exposes a GraphQL API that developers can use to build custom integrations or automate data entry.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Who maintains Traggo?$q$, $q$Traggo is a community-driven open-source project hosted under the traggo GitHub organization, with active forks continuing development.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$What technology is Traggo built on?$q$, $q$Traggo uses a Go-based backend server and a web client, and it is distributed as a Docker container for easy deployment.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Freelance and consulting time tracking$q$, $q$Freelancers tag time entries by client and project to track billable hours without committing to a rigid project structure.$q$, $q$Freelancers and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Privacy-first self-hosted tooling$q$, $q$Small teams or self-hosters run Traggo alongside other self-hosted apps to keep time-tracking data entirely off third-party servers.$q$, $q$Self-hosters and privacy-conscious small teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Personal productivity tracking$q$, $q$Individuals track how their time is spent across work, learning, and personal activities using flexible custom tags.$q$, $q$Individuals and homelab users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited tags and time entries","Multi-user support","Docker-based deployment","GraphQL API access","GPL-3.0 licensed source code"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$overview$q$, $q$What Is Traggo$q$, 2, ARRAY[$q$Traggo is an open-source, self-hosted time tracking application designed around tags rather than tasks or projects. Instead of creating a project hierarchy before you can log time, you simply start and stop a time span and attach any number of key-value tags to it, such as project equals website-redesign or type equals meeting. This tag-first approach makes Traggo especially flexible for freelancers, consultants, and small teams whose work does not fit neatly into a single fixed taxonomy.$q$, $q$Because Traggo is self-hosted, it appeals strongly to privacy-conscious users and homelab enthusiasts who do not want their time-tracking data stored on a third-party server. The application is distributed as a Docker image, so deployment typically involves running a container on a personal server, NAS device, or cloud VPS rather than signing up for a hosted account. There is no official managed cloud version; running an instance is the only way to use Traggo.$q$, $q$The project is maintained as open-source software under the GPL-3.0 license, with source code split across a Go-based server and a web-based client. Development has continued through the community, including maintained forks that keep dependencies and features current after periods of slower activity on the original repository.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Traggo's core feature is its tag-based data model: every tracked time span can carry multiple tags with arbitrary keys and values, letting users slice their time data along whatever dimensions matter to them, whether that is client, project, task type, or billing status. A built-in reporting view aggregates logged time by tag, making it possible to see, for example, total hours per client or per activity category without any manual spreadsheet work.$q$, $q$The application includes a visual timeline for reviewing and editing past entries, keyboard-driven quick entry for fast logging, and multi-user support so a small team can share a single self-hosted instance while keeping their own tagged history. A GraphQL API is available for developers who want to build custom integrations, scripts, or dashboards on top of their tracked data.$q$, $q$Because everything runs on infrastructure the user controls, Traggo avoids the recurring subscription costs, download limits, and data-export restrictions that are common with commercial, cloud-hosted time trackers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Traggo itself is completely free and always has been, since it is released as open-source software with no paid tiers, license keys, or feature gates. The only cost associated with using Traggo is whatever it costs to run the Docker container, whether that is a spare home server, a NAS, or a small cloud VPS, typically a few dollars a month at most for personal use.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d816c0d6-616e-417e-bf4c-30fc9be88134', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc2d5e9c-d0f2-485e-b895-ac90c8c8411f', $q$Unlimited podcasts and episodes$q$, $q$Host as many shows and episodes as needed on a single account at every pricing tier.$q$, 0);
