INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$E-commerce and CRM integrations$q$, $q$Connect Trengo to platforms like Shopify and HubSpot to bring customer context into conversations.$q$, 7);
