INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$What is Trengo used for?$q$, $q$Trengo unifies customer communication channels, including email, WhatsApp, live chat, social media, and voice, into one shared team inbox.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Where is Trengo based?$q$, $q$Trengo is headquartered in Utrecht, Netherlands.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$When was Trengo founded?$q$, $q$Trengo was founded in 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$How much does Trengo cost?$q$, $q$Plans start around 125 euros a month, roughly 133 US dollars, for 5 users and 100 conversations, scaling up through Boost and Pro tiers plus a custom Enterprise plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Does Trengo support WhatsApp?$q$, $q$Yes, Trengo integrates natively with the WhatsApp Business API for two-way messaging and automation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Is there a free trial of Trengo?$q$, $q$Trengo commonly offers a free trial period for prospective customers to evaluate the platform before subscribing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Does Trengo have AI features?$q$, $q$Yes, Trengo includes AI-powered chatbots and automation rules for conversation triage and routing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Who are Trengo's main competitors?$q$, $q$Trengo is commonly compared to Front, Zendesk, Intercom, and HubSpot Service Hub.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$E-commerce customer support$q$, $q$Manage WhatsApp, live chat, and email support for online stores from a single inbox.$q$, $q$Online retailers and e-commerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$SMB customer service consolidation$q$, $q$Bring scattered email, chat, and social channels into one shared inbox for a growing support team.$q$, $q$Small-to-midsize customer service teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$WhatsApp-based sales outreach$q$, $q$Use WhatsApp Business messaging and automation for outbound sales and lead engagement.$q$, $q$Sales and CRM teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Essentials$q$, $q$EUR125/month (~$133)$q$, $q$monthly or annual$q$, NULL, $q$["5 users","100 conversations per month","Shared team inbox","Live chat widget"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Boost$q$, $q$EUR185/month (~$196)$q$, $q$monthly or annual$q$, NULL, $q$["5 users","300 conversations per month","Automation rules","WhatsApp Business integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Pro$q$, $q$EUR310/month (~$329)$q$, $q$monthly or annual$q$, NULL, $q$["5 users","1,000 conversations per month","Advanced reporting","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$Enterprise$q$, $q$Custom$q$, $q$annual, sales-assisted$q$, NULL, $q$["Custom conversation volume","Dedicated account support","Advanced security","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$overview$q$, $q$What Is Trengo$q$, 2, ARRAY[$q$Trengo is a customer engagement platform founded in 2017 and based in Utrecht, Netherlands, built to unify the many channels customers use to reach a business, including email, WhatsApp, live chat, social media, and voice, into a single shared inbox. Rather than forcing support and sales teams to juggle separate apps for each channel, Trengo consolidates conversations so a team can respond from one place regardless of where a message originated.$q$, $q$The platform has become particularly well known for its deep WhatsApp Business API integration, which is a major differentiator in European and e-commerce markets where WhatsApp is a dominant customer communication channel, something many US-focused helpdesk tools support less natively.$q$, $q$Trengo has raised significant venture funding, including a 36 million dollar Series A round, and serves small-to-midsize businesses through larger enterprise customers with tiered plans that scale by team size and monthly conversation volume.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Trengo is a unified team inbox that pulls in messages from email, WhatsApp, live chat, Instagram, Facebook, and voice calls, letting agents see and respond to every conversation without switching tools. The WhatsApp Business API integration supports two-way messaging, broadcast campaigns, and automated flows, which is central to Trengo's appeal for e-commerce and consumer-facing brands.$q$, $q$AI-powered chatbots and rule-based automation handle first-line triage, routing, and frequently asked questions before a conversation reaches a human agent, while internal notes, assignment rules, and service-level agreement tracking help teams collaborate on shared conversations without confusion.$q$, $q$Trengo also includes a reporting and analytics dashboard for tracking response times and conversation volume, along with integrations to e-commerce and CRM platforms such as Shopify and HubSpot, letting customer context flow directly into support conversations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('463b249f-58f5-4f62-8f21-0f807fd8bd65', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Trengo's published plans are priced in euros and scale by both team size and monthly conversation volume. Essentials starts at 125 euros a month for 5 users and 100 conversations, Boost is 185 euros a month for 5 users and 300 conversations, and Pro is 310 euros a month for 5 users and 1,000 conversations; a custom-priced Enterprise plan is available for larger teams with higher volume or advanced security requirements.$q$, $q$Because all plans have a 5-user minimum and price out additional conversation volume, smaller teams that need more than the included conversation allowance, or teams larger than 5 users, should expect the effective monthly cost to rise beyond the listed starting price.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$TypeScript-native SDK$q$, $q$Define background jobs and durable tasks directly in TypeScript application code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Automatic retries$q$, $q$Failed tasks automatically retry and can resume durably without losing progress.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Task queues with concurrency control$q$, $q$Configure how many tasks run in parallel to manage load and resource usage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Elastic, fully-managed infrastructure$q$, $q$Workers scale automatically based on demand without manual infrastructure management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Built-in observability and tracing$q$, $q$Every run is logged and traceable for debugging long-running or multi-step tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Scheduled and recurring tasks$q$, $q$Run jobs on cron-style schedules alongside event-triggered tasks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$AI agent workflow support$q$, $q$Purpose-built primitives for running long-lived AI agent tasks reliably.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Self-hostable open-source core$q$, $q$Run Trigger.dev on your own infrastructure instead of the managed cloud if required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Open source with a genuinely self-hostable option$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$TypeScript-first developer experience tailored to modern web and AI stacks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Generous free plan with real usage credits rather than a hard feature cap$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Purpose-built for long-running and AI agent workflows, not just simple queues$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Backed by Y Combinator with active, ongoing development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Small, young company relative to established workflow platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Usage-based compute pricing can be difficult to forecast at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Requires TypeScript and coding knowledge, unlike no-code automation tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Fewer pre-built app integrations than no-code platforms like Zapier or Make$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Smaller community and ecosystem than more established job frameworks$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$What is Trigger.dev?$q$, $q$It is an open-source TypeScript platform for building background jobs, durable tasks, and AI agent workflows.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Is Trigger.dev free?$q$, $q$Yes, there is a free plan that includes monthly usage credits and core features, with paid plans starting at 10 dollars a month for higher limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Who founded Trigger.dev?$q$, $q$Trigger.dev was founded in 2022 by Matt Aitken, Eric Allam, Dan Patel, and James Ritchie.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Is Trigger.dev open source?$q$, $q$Yes, its core platform is open source and can be self-hosted in addition to using the managed cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Was Trigger.dev part of Y Combinator?$q$, $q$Yes, it went through Y Combinator's Winter 2023 (W23) batch.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$How is Trigger.dev priced?$q$, $q$Pricing combines a monthly plan fee with usage-based compute charges billed per second of execution, plus a small per-run invocation fee.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$How does Trigger.dev differ from Temporal?$q$, $q$Trigger.dev is TypeScript-first with a fully-managed cloud and simpler developer experience, aimed at web and AI engineering teams, rather than being a general-purpose, language-agnostic workflow engine.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Can I self-host Trigger.dev?$q$, $q$Yes, its open-source core can be self-hosted for teams that need to keep everything on their own infrastructure.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Long-running AI agent workflows$q$, $q$Run AI agent tasks reliably with retries, observability, and durable execution.$q$, $q$AI and machine learning engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$SaaS background job processing$q$, $q$Handle emails, webhooks, and data synchronization jobs outside the request-response cycle.$q$, $q$Product engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Scheduled task automation$q$, $q$Run recurring, cron-style jobs for developers who prefer defining automation in code.$q$, $q$Indie developers and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["$5/month included credits","20 concurrent runs","10 schedules","1-day log retention","5 team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Hobby$q$, $q$$10/month$q$, $q$monthly$q$, NULL, $q$["$10/month included credits","50 concurrent runs","100 schedules","7-day log retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Pro$q$, $q$$50/month$q$, $q$monthly$q$, NULL, $q$["$50/month included credits","200-plus concurrent runs","1,000-plus schedules","30-day log retention","Dedicated Slack support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$Enterprise$q$, $q$Custom$q$, $q$annual, sales-assisted$q$, NULL, $q$["Custom log retention","Single sign-on","SOC 2 and penetration test reports","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$overview$q$, $q$What Is Trigger.dev$q$, 2, ARRAY[$q$Trigger.dev is an open-source platform for building and running background jobs, durable long-running tasks, and AI agent workflows in TypeScript. It was founded in 2022 by Matt Aitken, Eric Allam, Dan Patel, and James Ritchie in London and went through Y Combinator's Winter 2023 batch before raising a seed round backed by early-stage investors.$q$, $q$The platform is aimed squarely at software engineering teams that need to run code reliably outside the request-response cycle of a typical web server, such as long-running AI agent tasks, scheduled jobs, data pipeline steps, and webhook processing that can take minutes or hours rather than milliseconds.$q$, $q$Its core is open source and can be self-hosted, while most users run their jobs on Trigger.dev's fully-managed cloud, which handles infrastructure, scaling, retries, and observability so engineering teams do not need to build and operate their own job queue and worker infrastructure from scratch.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Trigger.dev provides a TypeScript-native SDK for defining tasks, jobs, and workflows directly in application code, with automatic retries and durable execution so a task can recover from a failure or a deploy without losing progress. Task queues allow developers to control concurrency precisely, and elastic, fully-managed infrastructure scales workers up and down automatically based on load.$q$, $q$Every run is fully observable, with built-in tracing and detailed logs that make it possible to debug long-running or multi-step tasks the same way a developer would debug a normal function call. The platform also supports scheduled and recurring tasks using familiar cron-style syntax, alongside first-class support for building AI agent workflows.$q$, $q$Because the core SDK and server are open source, teams that need to keep everything in their own infrastructure can self-host Trigger.dev rather than relying on the managed cloud, while still getting the same developer experience and tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Trigger.dev's cloud pricing combines a monthly plan fee with usage-based compute and invocation costs. The Free plan includes 5 dollars of monthly credits, 20 concurrent runs, 10 schedules, and 1 day of log retention; Hobby is 10 dollars a month with more credits and higher limits; and Pro is 50 dollars a month with 200 or more concurrent runs, 1,000 or more schedules, 30-day log retention, and dedicated Slack support.$q$, $q$Beyond the included monthly credits, tasks are billed per second of execution time based on compute size, plus a small per-run invocation fee of about 0.000025 dollars per run. An Enterprise tier offers custom pricing with extended log retention, single sign-on, and compliance reports such as SOC 2 for organizations with stricter requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('caa46b4a-ddf7-473a-8793-845e45dd40b3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
