INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Kanban board view$q$, $q$Track tasks or project status directly within the note hierarchy using a Kanban layout.$q$, 5);
