INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Local SQLite storage with optional sync$q$, $q$Keep all data locally, with an optional self-hosted server for syncing across devices.$q$, 7);
