INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Strong privacy through local-first storage with no telemetry or vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Highly flexible unlimited-depth hierarchy with powerful note cloning$q$, 2);
