INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Mobile experience has historically lagged behind the desktop and server experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$The project underwent a maintenance-mode scare in 2024 before the community fork took over$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Is Trilium Notes free?$q$, $q$Yes, Trilium Notes is completely free and open source under the AGPL-3.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Who maintains Trilium Notes today?$q$, $q$The TriliumNext community organization maintains it, after original creator zadam moved the project to maintenance mode in 2024 and later transferred repository ownership.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Does Trilium Notes require the cloud?$q$, $q$No, all data is stored locally in a SQLite database, with an optional self-hosted sync server for accessing notes on multiple devices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$How is Trilium different from Notion or Evernote?$q$, $q$Trilium is self-hosted and open source, and it organizes notes in an unlimited-depth tree with note cloning rather than flat pages or notebooks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Can I use Trilium Notes on mobile?$q$, $q$Yes, though the desktop and server experience has traditionally been more feature-complete than mobile.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Does Trilium Notes support Markdown?$q$, $q$Yes, the editor supports Markdown-style shortcuts as well as Markdown import and export.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Is there a web clipper for Trilium Notes?$q$, $q$Yes, a browser extension lets users save web pages and screenshots directly into their note hierarchy.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$What license does Trilium Notes use?$q$, $q$It is released under the GNU Affero General Public License version 3 (AGPL-3.0).$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Personal knowledge base$q$, $q$Build a large, deeply organized second brain using unlimited-depth note hierarchies and cloning.$q$, $q$Researchers and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Self-hosted alternative to Evernote or OneNote$q$, $q$Move notes off third-party cloud services onto a self-hosted, privacy-respecting platform.$q$, $q$Privacy-focused individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Developer documentation and snippets$q$, $q$Organize technical documentation and code snippets with syntax highlighting and structured tags.$q$, $q$Software developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited notes and hierarchy depth","Local SQLite storage","Optional self-hosted sync server","Web clipper browser extension","Community-maintained under TriliumNext"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$overview$q$, $q$What Is Trilium Notes$q$, 2, ARRAY[$q$Trilium Notes is a free, open-source, self-hosted note-taking application designed for building large, deeply organized personal knowledge bases. It was first released in December 2017 by a developer known as zadam and has since become a well-known alternative to commercial note apps like Evernote, OneNote, and Notion for users who want full control over their data.$q$, $q$The application's defining feature is its hierarchical structure: instead of storing notes in flat notebooks or folders, Trilium organizes them as a tree of unlimited depth, and any note can be cloned to appear in multiple branches of that tree simultaneously without duplicating its underlying content. This makes it possible to build genuinely large, cross-referenced knowledge bases that stay navigable over time.$q$, $q$In January 2024, the original creator moved the project into maintenance mode, and a group of community contributors organized as TriliumNext to fork the project and keep it actively developed. That community fork eventually reunited with the original repository when zadam transferred ownership to the TriliumNext organization, which now continues developing and releasing the project as Trilium Notes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Trilium's core editor is a WYSIWYG interface that supports Markdown-style shortcuts and slash commands for quick formatting, alongside tables, images, math expressions, and code blocks with syntax highlighting, making it capable of handling both everyday notes and technical documentation. Notes can be tagged with labels and connected through relations, giving users a way to add structured metadata beyond the tree hierarchy alone.$q$, $q$Beyond plain note-taking, Trilium includes a built-in calendar for organizing events with day, week, month, and year views, and a Kanban board mode for tracking tasks or project status directly inside the note tree. A browser-based web-clipper extension lets users capture web pages or screenshots and file them straight into their knowledge base.$q$, $q$All data is stored in a local SQLite database rather than a proprietary cloud format, and users who want to access their notes across multiple devices can run a self-hosted sync server, keeping full control of their data without relying on any third-party service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Trilium Notes is entirely free and open source under the AGPL-3.0 license, with no subscription fees, license keys, or paid tiers of any kind. Since it is self-hosted or run locally, the only associated cost is optional hosting infrastructure if a user chooses to run a personal sync server; development is sustained by the open-source community rather than a commercial revenue model.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8a1e8900-232b-487e-a707-161bf160047b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
